	}
	if count == 0 {
		return ErrNotFound
	}

	if at.IsZero() {
		at = time.Now()
	}

	score := float64(at.Unix())
	zaddCmd := v.cli.B().Zadd().Key(v.lastActivityIndexKey).Score(score).Member(sessionID).Build()
	return v.cli.Do(ctx, zaddCmd).Error()
}

