	"time"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

type mockStore struct {
	sandboxes map[string]*types.SandboxInfo
}

func (m *mockStore) Ping(ctx context.Context) error {
	return nil
}

func (m *mockStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	if sb, ok := m.sandboxes[sessionID]; ok {
		return sb, nil
	}
	return nil, ErrNotFound
}

func (m *mockStore) StoreSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error {
	if sandboxStore == nil {
		return errors.New("sandbox is nil")
	}
	if sandboxStore.ExpiresAt.IsZero() {
		return errors.New("ExpiresAt is zero")
	}
	m.sandboxes[sandboxStore.SessionID] = sandboxStore
	return nil
}

func (m *mockStore) UpdateSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error {
	if _, ok := m.sandboxes[sandboxStore.SessionID]; !ok {
		return errors.New("key not exists")
	}
	m.sandboxes[sandboxStore.SessionID] = sandboxStore
	return nil
}

func (m *mockStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	delete(m.sandboxes, sessionID)
	return nil
}

func (m *mockStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}
	var result []*types.SandboxInfo
	for _, sb := range m.sandboxes {
		if sb.ExpiresAt.Before(before) {
			result = append(result, sb)
			if int64(len(result)) >= limit {
				break
			}
		}
	}
	return result, nil
}

func (m *mockStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}
	return nil, nil
}

func (m *mockStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if _, ok := m.sandboxes[sessionID]; !ok {
		return ErrNotFound
	}
	return nil
}

func (m *mockStore) Close() error {
	return nil
}

func TestStoreInterface(t *testing.T) {
	var s Store = &mockStore{sandboxes: make(map[string]*types.SandboxInfo)}
	ctx := context.Background()

	t.Run("StoreSandbox nil", func(t *testing.T) {
		err := s.StoreSandbox(ctx, nil)
		if err == nil {
			t.Error("expected error for nil sandbox")
		}
	})

	t.Run("StoreSandbox zero expiry", func(t *testing.T) {
		sb := &types.SandboxInfo{SessionID: "s1", ExpiresAt: time.Time{}}
		err := s.StoreSandbox(ctx, sb)
		if err == nil {
			t.Error("expected error for zero expiry")
		}
	})

	t.Run("StoreSandbox and Get", func(t *testing.T) {
		sb := &types.SandboxInfo{
			Kind:      "AgentRuntime",
			SessionID: "s2",
			ExpiresAt: time.Now().Add(time.Hour),
		}
		if err := s.StoreSandbox(ctx, sb); err != nil {
			t.Errorf("StoreSandbox failed: %v", err)
		}
		got, err := s.GetSandboxBySessionID(ctx, "s2")
		if err != nil {
			t.Errorf("GetSandboxBySessionID failed: %v", err)
		}
		if got.SessionID != "s2" {
			t.Errorf("expected s2, got %s", got.SessionID)
		}
	})

	t.Run("Get not found", func(t *testing.T) {
		_, err := s.GetSandboxBySessionID(ctx, "nonexistent")
		if !errors.Is(err, ErrNotFound) {
			t.Errorf("expected ErrNotFound, got %v", err)
		}
	})

	t.Run("Delete not found", func(t *testing.T) {
		if err := s.DeleteSandboxBySessionID(ctx, "nonexistent"); err != nil {
			t.Errorf("unexpected error: %v", err)
		}
	})

	t.Run("UpdateSandbox not found", func(t *testing.T) {
		sb := &types.SandboxInfo{SessionID: "nonexistent", ExpiresAt: time.Now()}
		err := s.UpdateSandbox(ctx, sb)
		if err == nil {
			t.Error("expected error for nonexistent key")
		}
	})

	t.Run("ListExpiredSandboxes zero limit", func(t *testing.T) {
		result, err := s.ListExpiredSandboxes(ctx, time.Now(), 0)
		if err != nil {
			t.Errorf("unexpected error: %v", err)
		}
		if result != nil {
			t.Error("expected nil for zero limit")
		}
	})

	t.Run("UpdateSessionLastActivity not found", func(t *testing.T) {
		err := s.UpdateSessionLastActivity(ctx, "nonexistent", time.Now())
		if !errors.Is(err, ErrNotFound) {
			t.Errorf("expected ErrNotFound, got %v", err)
		}
	})

	t.Run("Ping", func(t *testing.T) {
		if err := s.Ping(ctx); err != nil {
			t.Errorf("Ping failed: %v", err)
		}
	})

	t.Run("Close", func(t *testing.T) {
		if err := s.Close(); err != nil {
			t.Errorf("Close failed: %v", err)
		}
	})
}

