package router

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"sync"
	"time"

	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/api"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
)

type SessionManager interface {
	GetSession(ctx context.Context, sessionID string) (*types.Session, error)
	CreateSession(ctx context.Context, sessionID string, metadata map[string]interface{}) (*types.Session, error)
	DeleteSession(ctx context.Context, sessionID string) error
	HandleAgentInvoke(ctx context.Context, req *api.AgentInvokeRequest) (*api.AgentInvokeResponse, error)
	HandleCodeInterpreterInvoke(ctx context.Context, req *api.CodeInterpreterInvokeRequest) (*api.CodeInterpreterInvokeResponse, error)
	ForwardToSandbox(ctx context.Context, sessionID string, payload []byte) ([]byte, error)
}

type sessionManager struct {
	store              store.Storage
	jwtManager         *JWTManager
	workloadManagerURL string
	sessions           sync.Map
	sessionTTL         time.Duration
	maxPayloadSize     int64
	httpClient         *http.Client
}

func NewSessionManager(ctx context.Context, store store.Storage, jwtManager *JWTManager, workloadManagerURL string) (*sessionManager, error) {
	mgr := &sessionManager{
		store:              store,
		jwtManager:         jwtManager,
		workloadManagerURL: workloadManagerURL,
		sessionTTL:         30 * time.Minute,
		maxPayloadSize:     10 * 1024 * 1024,
		httpClient: &http.Client{
			Timeout: 60 * time.Second,
		},
	}

	if err := mgr.initializeFromStore(ctx); err != nil {
		klog.Warningf("Failed to initialize sessions from store: %v", err)
	}

	return mgr, nil
}

func (m *sessionManager) initializeFromStore(ctx context.Context) error {
	sessions, err := m.store.ListSessions(ctx)
	if err != nil {
		return fmt.Errorf("failed to list sessions: %w", err)
	}

	for _, session := range sessions {
		m.sessions.Store(session.ID, session)
		klog.V(4).Infof("Loaded session %s from store", session.ID)
	}

	return nil
}

func (m *sessionManager) GetSession(ctx context.Context, sessionID string) (*types.Session, error) {
	if sessionID == "" {
		return nil, fmt.Errorf("session ID is required")
	}

	if val, ok := m.sessions.Load(sessionID); ok {
		session := val.(*types.Session)
		session.LastAccessTime = time.Now()
		return session, nil
	}

	session, err := m.store.GetSession(ctx, sessionID)
	if err != nil {
		return nil, fmt.Errorf("session not found: %w", err)
	}

	session.LastAccessTime = time.Now()
	m.sessions.Store(sessionID, session)
	return session, nil
}

func (m *sessionManager) CreateSession(ctx context.Context, sessionID string, metadata map[string]interface{}) (*types.Session, error) {
	if sessionID == "" {
		return nil, fmt.Errorf("session ID is required")
	}

	if _, exists := m.sessions.Load(sessionID); exists {
		return nil, fmt.Errorf("session already exists: %s", sessionID)
	}

	session := &types.Session{
		ID:             sessionID,
		Metadata:       metadata,
		CreatedAt:      time.Now(),
		LastAccessTime: time.Now(),
		Status:         types.SessionStatusActive,
	}

	if err := m.store.SaveSession(ctx, session); err != nil {
		return nil, fmt.Errorf("failed to save session: %w", err)
	}

	m.sessions.Store(sessionID, session)
	klog.V(4).Infof("Created new session %s", sessionID)

	return session, nil
}

func (m *sessionManager) DeleteSession(ctx context.Context, sessionID string) error {
	if sessionID == "" {
		return fmt.Errorf("session ID is required")
	}

	m.sessions.Delete(sessionID)

	if err := m.store.DeleteSession(ctx, sessionID); err != nil {
		return fmt.Errorf("failed to delete session: %w", err)
	}

	klog.V(4).Infof("Deleted session %s", sessionID)
	return nil
}

func (m *sessionManager) HandleAgentInvoke(ctx context.Context, req *api.AgentInvokeRequest) (*api.AgentInvokeResponse, error) {
	if req == nil {
		return nil, fmt.Errorf("request is nil")
	}

	session, err := m.GetSession(ctx, req.SessionID)
	if err != nil {
		session, err = m.CreateSession(ctx, req.SessionID, req.Metadata)
		if err != nil {
			return nil, fmt.Errorf("failed to create session: %w", err)
		}
	}

	token, err := m.jwtManager.GenerateToken(session.ID, session.Metadata)
	if err != nil {
		return nil, fmt.Errorf("failed to generate token: %w", err)
	}

	payload, err := json.Marshal(req)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal request: %w", err)
	}

	response, err := m.ForwardToSandbox(ctx, session.ID, payload)
	if err != nil {
		return nil, fmt.Errorf("forward to sandbox failed: %w", err)
	}

	return &api.AgentInvokeResponse{
		SessionID: session.ID,
		Token:     token,
		Result:    response,
	}, nil
}

func (m *sessionManager) HandleCodeInterpreterInvoke(ctx context.Context, req *api.CodeInterpreterInvokeRequest) (*api.CodeInterpreterInvokeResponse, error) {
	if req == nil {
		return nil, fmt.Errorf("request is nil")
	}

	session, err := m.GetSession(ctx, req.SessionID)
	if err != nil {
		session, err = m.CreateSession(ctx, req.SessionID, req.Metadata)
		if err != nil {
			return nil, fmt.Errorf("failed to create session: %w", err)
		}
	}

	token, err := m.jwtManager.GenerateToken(session.ID, session.Metadata)
	if err != nil {
		return nil, fmt.Errorf("failed to generate token: %w", err)
	}

	payload, err := json.Marshal(req)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal request: %w", err)
	}

	response, err := m.ForwardToSandbox(ctx, session.ID, payload)
	if err != nil {
		return nil, fmt.Errorf("forward to sandbox failed: %w", err)
	}

	return &api.CodeInterpreterInvokeResponse{
		SessionID: session.ID,
		Token:     token,
		Result:    response,
	}, nil
}

func (m *sessionManager) ForwardToSandbox(ctx context.Context, sessionID string, payload []byte) ([]byte, error) {
	if len(payload) > int(m.maxPayloadSize) {
		return nil, fmt.Errorf("payload size exceeds maximum allowed size: %d > %d", len(payload), m.maxPayloadSize)
	}

	url := fmt.Sprintf("%s/api/v1/sandbox/invoke", m.workloadManagerURL)

	req, err := http.NewRequestWithContext(ctx, http.MethodPost, url, bytes.NewReader(payload))
	if err != nil {
		return nil, fmt.Errorf("failed to create request: %w", err)
	}

	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("X-Session-ID", sessionID)

	resp, err := m.httpClient.Do(req)
	if err != nil {
		return nil, fmt.Errorf("request to sandbox failed: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		body, _ := io.ReadAll(io.LimitReader(resp.Body, 1024))
		return nil, fmt.Errorf("sandbox returned error status %d: %s", resp.StatusCode, string(body))
	}

	response, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("failed to read response: %w", err)
	}

	return response, nil
}

var _ SessionManager = (*sessionManager)(nil)

