func (r *redisStore) GetSession(ctx context.Context, sessionID string) (*types.Session, error) {
	key := r.sessionKey(sessionID)
	data, err := r.cli.Get(ctx, key).Bytes()
	if err != nil {
		if errors.Is(err, redis.Nil) {
			return nil, ErrNotFound
		}
		return nil, err
	}

	var session types.Session
	if err := json.Unmarshal(data, &session); err != nil {
		return nil, err
	}
	return &session, nil
}

func (r *redisStore) SaveSession(ctx context.Context, session *types.Session) error {
	data, err := json.Marshal(session)
	if err != nil {
		return err
	}

	key := r.sessionKey(session.SessionID)
	return r.cli.Set(ctx, key, data, 0).Err()
}

func (r *redisStore) DeleteSession(ctx context.Context, sessionID string) error {
	key := r.sessionKey(sessionID)
	return r.cli.Del(ctx, key).Err()
}

func (r *redisStore) ListSessions(ctx context.Context) ([]*types.Session, error) {
	keys, err := r.cli.Keys(ctx, r.sessionPrefix+"*").Result()
	if err != nil {
		return nil, err
	}

	var sessions []*types.Session
	for _, key := range keys {
		data, err := r.cli.Get(ctx, key).Bytes()
		if err != nil {
			continue
		}
		var session types.Session
		if err := json.Unmarshal(data, &session); err != nil {
			continue
		}
		sessions = append(sessions, &session)
	}
	return sessions, nil
}

