	data, err := json.Marshal(sandboxStore)
	if err != nil {
		return err
	}

	key := v.sessionKey(sandboxStore.SessionID)
	setCmd := v.cli.B().Setnx().Key(key).Value(string(data)).Build()
	if err := v.cli.Do(ctx, setCmd).Error(); err != nil {
		return err
	}

	score := float64(sandboxStore.ExpiresAt.Unix())
	expiryCmd := v.cli.B().Zadd().Key(v.expiryIndexKey).ScoreMember().ScoreMember(score, sandboxStore.SessionID).Build()
	if err := v.cli.Do(ctx, expiryCmd).Error(); err != nil {
		return err
	}

	activityScore := float64(time.Now().Unix())
	activityCmd := v.cli.B().Zadd().Key(v.lastActivityIndexKey).ScoreMember().ScoreMember(activityScore, sandboxStore.SessionID).Build()
	if err := v.cli.Do(ctx, activityCmd).Error(); err != nil {
		return err
	}

	return nil
}

