	return v.cli.Do(ctx, zaddCmd).Error()
}

func (v *valkeyStore) Close() error {
	v.cli.Close()
	return nil
}

func (v *valkeyStore) GetSession(ctx context.Context, sessionID string) (*types.Session, error) {
	key := v.sessionKey(sessionID)
	result := v.cli.B().Get().Key(key).Build()
	resp := v.cli.Do(ctx, result)
	if resp.Error() != nil {
		if errors.Is(resp.Error(), valkey.Nil) {
			return nil, ErrNotFound
		}
		return nil, resp.Error()
	}

	data := resp.String()
	var session types.Session
	if err := json.Unmarshal([]byte(data), &session); err != nil {
		return nil, err
	}
	return &session, nil
}

func (v *valkeyStore) SaveSession(ctx context.Context, session *types.Session) error {
	data, err := json.Marshal(session)
	if err != nil {
		return err
	}

	key := v.sessionKey(session.SessionID)
	cmd := v.cli.B().Set().Key(key).Value(string(data)).Build()
	return v.cli.Do(ctx, cmd).Error()
}

func (v *valkeyStore) DeleteSession(ctx context.Context, sessionID string) error {
	key := v.sessionKey(sessionID)
	cmd := v.cli.B().Del().Key(key).Build()
	return v.cli.Do(ctx, cmd).Error()
}

func (v *valkeyStore) ListSessions(ctx context.Context) ([]*types.Session, error) {
	pattern := v.sessionPrefix + "*"
	result := v.cli.B().Keys().Pattern(pattern).Build()
	resp := v.cli.Do(ctx, result)
	keys, err := resp.AsStrSlice()
	if err != nil {
		return nil, err
	}

	var sessions []*types.Session
	for _, key := range keys {
		cmd := v.cli.B().Get().Key(key).Build()
		resp := v.cli.Do(ctx, cmd)
		if resp.Error() != nil {
			continue
		}
		data := resp.String()
		var session types.Session
		if err := json.Unmarshal([]byte(data), &session); err != nil {
			continue
		}
		sessions = append(sessions, &session)
	}
	return sessions, nil
