package router

import (
	"context"
	"crypto/tls"
	"fmt"
	"net"
	"net/http"
	"time"

	"github.com/gin-gonic/gin"
	"golang.org/x/net/http2"
	"golang.org/x/net/http2/h2c"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/store"
)

const (
	readHeaderTimeout = 5 * time.Second
	readTimeout       = 30 * time.Second
	writeTimeout      = 30 * time.Second
	idleTimeout       = 120 * time.Second
)

func NewServer(ctx context.Context, cfg *Config, store store.Storage) (*Server, error) {
	if cfg.Debug {
		gin.SetMode(gin.DebugMode)
	} else {
		gin.SetMode(gin.ReleaseMode)
	}

	engine := gin.New()
	engine.Use(gin.Recovery())
	if cfg.Debug {
		engine.Use(gin.Logger())
	}

	jwtManager, err := NewJWTManager(cfg.JWTKeySecretNamespace)
	if err != nil {
		return nil, fmt.Errorf("failed to create JWT manager: %w", err)
	}

	sessionManager, err := NewSessionManager(ctx, store, jwtManager, cfg.WorkloadManagerURL)
	if err != nil {
		return nil, fmt.Errorf("failed to create session manager: %w", err)
	}

	tlsConfig := &tls.Config{
		MinVersion:       tls.VersionTLS12,
		CurvePreferences: []tls.CurveID{tls.CurveP256, tls.X25519},
		CipherSuites: []uint16{
			tls.TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384,
			tls.TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384,
			tls.TLS_ECDHE_ECDSA_WITH_CHACHA20_POLY1305,
			tls.TLS_ECDHE_RSA_WITH_CHACHA20_POLY1305,
		},
		GetCertificate: jwtManager.GetTLSCertificate,
	}

	srv := &Server{
		config:     cfg,
		engine:     engine,
		sessionMgr: sessionManager,
		jwtManager: jwtManager,
		store:      store,
		tlsConfig:  tlsConfig,
		shutdownCh: make(chan struct{}),
	}

	srv.registerRoutes()
	srv.setupHTTPServer()
	srv.setupHTTP2Server()

	return srv, nil
}

func (s *Server) registerRoutes() {
	s.engine.GET("/health/live", s.handleHealthLive)
	s.engine.GET("/health/ready", s.handleHealthReady)
	s.engine.POST("/agent/invoke", s.handleAgentInvoke)
	s.engine.POST("/code-interpreter/invoke", s.handleCodeInterpreterInvoke)
}

func (s *Server) setupHTTPServer() {
	s.httpServer = &http.Server{
		Addr:              fmt.Sprintf(":%d", s.config.Port),
		Handler:           h2c.NewHandler(s.engine, &http2.Server{}),
		ReadHeaderTimeout: readHeaderTimeout,
		ReadTimeout:       readTimeout,
		WriteTimeout:      writeTimeout,
		IdleTimeout:       idleTimeout,
		TLSConfig:         s.tlsConfig,
	}
}

func (s *Server) setupHTTP2Server() {
	s.http2Server = &http2.Server{
		MaxConcurrentStreams: 250,
		MaxReadFrameSize:     1048576,
		IdleTimeout:          idleTimeout,
	}

	listener, err := net.Listen("tcp", fmt.Sprintf(":%d", s.config.Port+1))
	if err != nil {
		klog.Warningf("Failed to create HTTP/2 listener on port %d: %v", s.config.Port+1, err)
		return
	}

	s.http2Server.ServeTLS(listener, "", "")
}

func (s *Server) Start(ctx context.Context) error {
	klog.Infof("Starting server on port %d", s.config.Port)

	go func() {
		if err := s.httpServer.ListenAndServeTLS("", ""); err != nil && err != http.ErrServerClosed {
			klog.Errorf("HTTP server error: %v", err)
		}
	}()

	s.wg.Add(1)
	go func() {
		defer s.wg.Done()
		<-ctx.Done()
		klog.Info("Context cancelled, initiating shutdown")
		close(s.shutdownCh)
	}()

	return nil
}

func (s *Server) Shutdown(ctx context.Context) error {
	var err error
	s.shutdownOnce.Do(func() {
		klog.Info("Shutting down server")

		shutdownCtx, cancel := context.WithTimeout(ctx, 30*time.Second)
		defer cancel()

		if s.httpServer != nil {
			if shutdownErr := s.httpServer.Shutdown(shutdownCtx); shutdownErr != nil {
				err = fmt.Errorf("HTTP server shutdown error: %w", shutdownErr)
			}
		}

		if s.http2Server != nil {
			s.http2Server.Shutdown(shutdownCtx)
		}

		s.wg.Wait()
		klog.Info("Server shutdown complete")
	})
	return err
}

